import React from "react";
import { useApp } from "../context/AppContext";

const Navbar = React.memo(function Navbar() {
  const { state, dispatch } = useApp();
  const { user, page } = state;

  return (
    <nav style={styles.nav}>
      <div
        style={styles.brand}
        onClick={() => dispatch({ type: "SET_PAGE", payload: "dashboard" })}
      >
        ◆ <span style={{ color: "var(--gold)" }}>Grand</span>Luxe
      </div>

      <div style={styles.links}>
        <button
          className={`nav-link${page === "dashboard" || page === "room" ? " active" : ""}`}
          style={styles.link}
          onClick={() => dispatch({ type: "SET_PAGE", payload: "dashboard" })}
        >
          Rooms
        </button>
        <button
          className={`nav-link${page === "bookings" ? " active" : ""}`}
          style={styles.link}
          onClick={() => dispatch({ type: "SET_PAGE", payload: "bookings" })}
        >
          My Bookings
          {state.bookings.length > 0 && (
            <span style={styles.badge}>{state.bookings.length}</span>
          )}
        </button>
      </div>

      <div style={styles.right}>
        <span style={{ fontSize: 13, color: "var(--muted)" }}>{user?.name}</span>
        <div style={styles.avatar}>{user?.name?.[0]}</div>
        <button
          className="btn btn-ghost"
          onClick={() => dispatch({ type: "LOGOUT" })}
        >
          Sign out
        </button>
      </div>
    </nav>
  );
});

const styles = {
  nav: {
    background: "var(--surface)", borderBottom: "1px solid var(--border)",
    padding: "0 40px", display: "flex", alignItems: "center",
    height: 64, position: "sticky", top: 0, zIndex: 100,
  },
  brand: {
    fontFamily: "'Cormorant Garamond', serif", fontSize: 26,
    fontWeight: 600, color: "var(--ink)", marginRight: 48,
    cursor: "pointer",
  },
  links: { display: "flex", gap: 4, flex: 1 },
  link: {
    padding: "8px 16px", borderRadius: "var(--radius)", fontSize: 13,
    color: "var(--muted)", cursor: "pointer", border: "none",
    background: "none", display: "flex", alignItems: "center", gap: 6,
  },
  right: { display: "flex", alignItems: "center", gap: 16 },
  avatar: {
    width: 34, height: 34, borderRadius: "50%", background: "var(--ink)",
    color: "var(--gold)", display: "flex", alignItems: "center",
    justifyContent: "center", fontSize: 13, fontWeight: 600,
  },
  badge: {
    background: "var(--gold)", color: "var(--ink)", borderRadius: 20,
    fontSize: 10, fontWeight: 700, padding: "2px 6px",
  },
};

export default Navbar;
